<#
.SYNOPSIS
    getdocker2
#>
Write-Host '? HARD-RESETTING DOCKER DESKTOP  ' -fo Yellow; Enable-WindowsOptionalFeature -Online -FeatureName Microsoft-Windows-Subsystem-Linux -NoRestart -ErrorAction SilentlyContinue | Out-Null; Enable-WindowsOptionalFeature -Online -FeatureName VirtualMachinePlatform -NoRestart -ErrorAction SilentlyContinue | Out-Null; Enable-WindowsOptionalFeature -Online -FeatureName Microsoft-Hyper-V-All -NoRestart -ErrorAction SilentlyContinue | Out-Null; try { winget uninstall -e --id Docker.DockerDesktop --silent --force --accept-source-agreements } catch {}; $cached=@(Get-ChildItem "$env:ProgramData\DockerDesktop\installers","$env:ProgramFiles\Docker" -Recurse -Filter "Docker Desktop Installer*.exe" -ea 0 | Sort-Object LastWriteTime -Descending | Select-Object -First 1); if($cached){ Start-Process $cached.FullName -Wait -ArgumentList 'uninstall','--quiet' }; Stop-Process -Name com.docker.backend,com.docker.service,'Docker Desktop' -Force -ea 0; wsl --terminate docker-desktop 2>$null; wsl --terminate docker-desktop-data 2>$null; wsl --unregister docker-desktop 2>$null; wsl --unregister docker-desktop-data 2>$null; Remove-Item "$env:ProgramFiles\Docker","$env:ProgramData\Docker","$env:ProgramData\DockerDesktop","$env:LOCALAPPDATA\Docker*","$env:APPDATA\Docker*","$env:USERPROFILE\.docker" -Recurse -Force -ea 0; Remove-Item 'HKLM:\SOFTWARE\Docker Inc.','HKCU:\SOFTWARE\Docker Inc.','HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\Docker Desktop' -Recurse -Force -ea 0; $dl="$env:TEMP\dockerdesktop_installer.exe"; Invoke-WebRequest 'https://desktop.docker.com/win/main/amd64/Docker%20Desktop%20Installer.exe' -UseBasicParsing -OutFile $dl; $p=Start-Process $dl -Wait -PassThru -ArgumentList 'install','--quiet','--accept-license'; if($p.ExitCode -eq 0){ $exe=Get-ChildItem "$env:ProgramFiles\Docker" -Recurse -Filter 'Docker Desktop.exe' -ea 0 | Select-Object -First 1; if($exe){ Write-Host '? Docker Desktop installed   launching  ' -fo Green; Start-Process $exe.FullName } else { Write-Warning 'Install finished but Docker Desktop.exe not found' } } else { Write-Warning "Installer failed with exit code $($p.ExitCode)" }
